from flask import Flask, request, redirect, url_for
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# In a real application, use a secure method to store passwords
hashed_password = generate_password_hash("mysecretpassword")

@app.route('/')
def index():
    auth = request.authorization
    if auth and check_password_hash(hashed_password, auth.password):
        return f"Welcome, {auth.username}!"
    return redirect(url_for('login'))

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        # Normally, you would check the username and password against a database
        if request.form['username'] == 'myuser' and request.form['password'] == 'mysecretpassword':
            return redirect(url_for('index'))
